SELECT avi_mgr_seq, rqst_mgr_seq, file_seq, file_nm, down_cnt, sec_st_dat, sec_ed_dat, bak_st_dat, bak_ed_dat, enc_st_dat, enc_ed_dat, mak_st_dat, mak_en_dat, work_stat_cd, work_rslt_msg, reenc_yn, sha_cde, md5_cde

