SELECT work.avi_mgr_seq, work.rqst_mgr_seq, work.file_seq, work.file_nm , work.down_cnt, work.sec_st_dat, work.sec_ed_dat, work.bak_st_dat, work.bak_ed_dat , work.enc_st_dat, work.enc_ed_dat, work.mak_st_dat, work.mak_en_dat , work.work_stat_cd, work.work_rslt_msg, work.reenc_yn, work.sha_cde, work.md5_cde , avi.cctv_mgr_no , rqst.reqst_id, rqst.reqst_dat, rqst.acpt_user_id, rqst.acpt_dat , cctv_no_rel.cctv_nm, cctv_model.model_nm , CASE WHEN renew2.mgr_seq is not null AND renew2.acpt_yn = 'Y' THEN renew2.play_limit_cnt ELSE CASE WHEN renew1.mgr_seq is not null AND renew1.acpt_yn = 'Y' THEN renew1.play_limit_cnt ELSE avi.play_limit_cnt END END AS play_limit_cnt , CASE WHEN renew2.mgr_seq is not null AND renew2.acpt_yn = 'Y' THEN renew2.play_limit_dat ELSE CASE WHEN renew1.mgr_seq is not null AND renew1.acpt_yn = 'Y' THEN renew1.play_limit_dat ELSE avi.play_limit_dat END END AS play_limit_dat
FROM xeus.crms_trans_work AS work LEFT JOIN xeus.crms_trans_avi AS avi ON work.avi_mgr_seq = avi.mgr_seq AND work.rqst_mgr_seq = avi.rqst_mgr_seq LEFT JOIN xeus.crms_trans_rqst AS rqst ON rqst.mgr_seq = avi.rqst_mgr_seq AND avi.mgr_seq = work.avi_mgr_seq LEFT JOIN xeus.asset_cctv AS cctv_no_rel ON cctv_no_rel.mgr_no = avi.cctv_mgr_no LEFT JOIN xeus.asset_cctv_model AS cctv_model ON cctv_no_rel.md_mgr_no = cctv_model.mgr_no LEFT JOIN xeus.crms_rqst_renew AS renew1 ON renew1.rqst_mgr_seq = work.rqst_mgr_seq AND renew1.avi_mgr_seq = work.avi_mgr_seq AND renew1.file_seq = work.file_seq AND renew1.renew_typ = '11' LEFT JOIN xeus.crms_rqst_renew AS renew2 ON renew2.rqst_mgr_seq = work.rqst_mgr_seq AND renew2.avi_mgr_seq = work.avi_mgr_seq AND renew2.file_seq = work.file_seq AND renew2.renew_typ = '12'
AND avi_mgr_seq = #{aviMgrSeq}::numeric
AND rqst_mgr_seq = #{rqstMgrSeq}::numeric
AND file_seq = #{fileSeq}::numeric
AND file_nm = #{fileNm}
AND down_cnt = #{downCnt}::numeric
AND sec_st_dat = #{secStDat}
AND sec_ed_dat = #{secEdDat}
AND bak_st_dat = #{bakStDat}
AND bak_ed_dat = #{bakEdDat}
AND enc_st_dat = #{encStDat}
AND enc_ed_dat = #{encEdDat}
AND mak_st_dat = #{makStDat}
AND mak_en_dat = #{makEnDat}
AND work_stat_cd = #{workStatCd}
AND work_rslt_msg = #{workRsltMsg}
AND reenc_yn = #{reencYn}
AND sha_cde = #{shaCde}
AND md5_cde = #{md5Cde}

